    --border-card: #eadef7;
    --radius: 10px;
  }

  .nodo7-container {
    font-family: 'Segoe UI', Roboto, Helvetica, Arial, sans-serif;
    color: var(--text-dark);
    max-width: 1050px;
    margin: 0 auto;
    padding: 15px;
    box-sizing: border-box;
  }

  /* Cabecera */
  .nodo7-header {
    display: flex;
    align-items: center;
    gap: 15px;
    margin-bottom: 20px;
  }

  .nodo7-number {
    background-color: var(--primary-purple);
    color: white;
    font-weight: bold;
    font-size: 24px;
    width: 45px;
    height: 45px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
  }

  .nodo7-title {
    color: var(--primary-purple);
    font-size: 26px;
    font-weight: 800;
    text-transform: uppercase;
    margin: 0;
  }

  /* Introducción */
  .nodo7-intro {
    background-color: var(--bg-light);
    border-left: 5px solid var(--primary-purple);
    padding: 15px 20px;
    margin-bottom: 30px;
    border-radius: 0 var(--radius) var(--radius) 0;
  }
  .nodo7-intro h3 {
    margin: 0 0 5px 0;
    color: var(--primary-purple);
    font-size: 18px;
  }
  .nodo7-intro p {
    margin: 0;
    font-size: 15px;
    color: #555;
  }

  /* Grid de Herramientas Recomendadas */
  .tools-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(230px, 1fr));
    gap: 20px;
    margin-bottom: 40px;
  }

  .tool-card {
    background: #fff;
    border: 1px solid var(--border-card);
    border-radius: var(--radius);
    padding: 20px;
    text-align: center;
    box-shadow: 0 4px 6px rgba(116, 68, 176, 0.05);
    display: flex;
    flex-direction: column;
    justify-content: space-between;
  }

  .tool-name {
    font-weight: bold;
    font-size: 16px;
    color: var(--primary-purple);
    text-transform: uppercase;
    margin-bottom: 10px;
  }

  .tool-use {
    font-size: 14px;
    color: #666;
    margin-bottom: 20px;
    line-height: 1.4;
  }

  /* Botones estilo imagen */
  .btn-purple {
    background-color: var(--primary-purple);
    color: white !important;
    text-decoration: none !important;
    padding: 10px 15px;
    border-radius: 6px;
    font-size: 14px;
    font-weight: 600;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 8px;
    transition: background 0.2s ease;
  }
  .btn-purple:hover {
    background-color: var(--primary-purple-hover);
  }

  /* Sección de elementos incrustados interactivos */
  .embed-section {
    margin-top: 30px;
  }

  .embed-section h3 {
    color: var(--primary-purple);
    border-bottom: 2px solid var(--border-card);
    padding-bottom: 8px;
    margin-bottom: 20px;
    font-size: 20px;
  }

  .embed-container {
    position: relative;
    overflow: hidden;
    width: 100%;
    padding-top: 56.25%; /* Relación de aspecto 16:9 */
    margin-bottom: 25px;
    border-radius: var(--radius);
    border: 1px solid var(--border-card);
    box-shadow: 0 4px 10px rgba(0,0,0,0.05);
  }

  .embed-container iframe {
    position: absolute;
    top: 0;
    left: 0;
    bottom: 0;
    right: 0;
    width: 100%;
    height: 100%;
    border: none;
  }

  .grid-two-columns {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 20px;
  }

  /* Responsive */
  @media (max-width: 768px) {
    .grid-two-columns {
      grid-template-columns: 1fr;
    }
    .nodo7-title {
      font-size: 20px;
    }
  }
</style>
